// LBF-E-Mail-Template für Lager-Benachrichtigungen.
// Wird von lager-alerts.pb.js via require() genutzt (kein eigener Hook, da
// Dateiname nicht auf .pb.js endet -> wird nicht automatisch ausgeführt).
//
// Stil exakt wie das Responda-Transaktionsmail-Template: eingebettete Atkinson
// Hyperlegible (400/700), Logo im dunkelroten Header, LBF-Farben.

const FONT_400 = "";

const FONT_700 = "";

const LOGO_B64 = "";

function buildAlertHtml(low, expired, expiring, lead) {
  const section = (title, color, arr) => arr.length ? (
    '<div style="margin-bottom:22px;">' +
    '<div style="font-size:10px;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:#600812;margin-bottom:10px;font-family:\'Atkinson Hyperlegible\',Georgia,serif;">' + title + '</div>' +
    '<div style="background:#faf9f7;border-left:3px solid ' + color + ';border-radius:8px;padding:4px 16px;">' +
    arr.map(x => '<div style="font-size:15px;color:#1a0e08;padding:9px 0;border-bottom:1px solid rgba(96,8,18,0.06);font-family:\'Atkinson Hyperlegible\',Georgia,serif;">' + x + '</div>').join('') +
    '</div></div>'
  ) : ''
  const sections =
    section('Unter Mindestbestand', '#600812', low) +
    section('Abgelaufen', '#dc2626', expired) +
    section('Läuft bald ab (' + lead + ' Tage)', '#d97706', expiring)

  return `<!DOCTYPE html>
<html lang="de">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Bestandswarnungen</title>
  <style>
    @font-face {
      font-family: 'Atkinson Hyperlegible';
      font-style: normal;
      font-weight: 400;
      src: url(data:font/woff2;base64,${FONT_400}) format('woff2');
    }
    @font-face {
      font-family: 'Atkinson Hyperlegible';
      font-style: normal;
      font-weight: 700;
      src: url(data:font/woff2;base64,${FONT_700}) format('woff2');
    }
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { background-color: #faf9f7; font-family: 'Atkinson Hyperlegible', Georgia, serif; -webkit-text-size-adjust: 100%; }
    @media only screen and (max-width: 480px) {
      .wrapper  { padding: 16px 10px !important; }
      .header   { padding: 30px 20px 26px !important; }
      .h-title  { font-size: 22px !important; }
      .logo-img { width: 52px !important; height: 55px !important; }
      .body     { padding: 26px 18px !important; }
      .greeting { font-size: 16px !important; }
      .footer   { padding: 16px 18px !important; }
    }
  </style>
</head>
<body style="background-color:#faf9f7;margin:0;padding:0;">
  <div class="wrapper" style="max-width:600px;margin:0 auto;padding:40px 20px;">
    <div style="background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 2px 16px rgba(0,0,0,0.08);">
      <div class="header" style="background:#600812;padding:40px 36px 36px;text-align:center;">
        <div style="width:68px;height:68px;border-radius:50%;background:#3d0408;border:1.5px solid rgba(253,232,216,0.2);margin:0 auto 16px;overflow:hidden;display:inline-flex;align-items:center;justify-content:center;">
          <img class="logo-img" src="data:image/svg+xml;base64,${LOGO_B64}" width="54" height="57" alt="Responda" style="display:block;width:54px;height:57px;" />
        </div>
        <div style="font-size:11px;font-weight:700;letter-spacing:0.22em;text-transform:uppercase;color:rgba(253,232,216,0.55);margin-bottom:10px;font-family:'Atkinson Hyperlegible',Georgia,serif;">Responda</div>
        <div class="h-title" style="font-size:26px;font-weight:700;font-style:italic;color:#fde8d8;font-family:'Atkinson Hyperlegible',Georgia,serif;line-height:1.2;">Bestandswarnungen</div>
      </div>

      <div class="body" style="padding:40px 36px;">
        <div class="greeting" style="font-size:17px;color:#1a0e08;line-height:1.7;margin-bottom:28px;font-family:'Atkinson Hyperlegible',Georgia,serif;">
          Hallo,<br><br>
          folgende Artikel in deinem Lager brauchen Aufmerksamkeit:
        </div>

        ${sections}

        <div style="text-align:center;margin:32px 0 8px;">
          <a class="btn" href="https://app.responda.systems/lager" style="display:inline-block;background:#600812;color:#ffffff;text-decoration:none;font-family:'Atkinson Hyperlegible',Georgia,serif;font-size:16px;font-weight:700;letter-spacing:0.03em;padding:18px 48px;border-radius:12px;">
            Zum Lager
          </a>
        </div>

        <div style="height:1px;background:rgba(96,8,18,0.08);margin:28px 0;"></div>

        <div style="font-size:13px;font-style:italic;color:#8a7a68;line-height:1.65;font-family:'Atkinson Hyperlegible',Georgia,serif;">
          Du erhältst diese Nachricht, weil du Lager-Benachrichtigungen aktiviert hast. Ändern kannst du das in der Responda-App unter Lager &rarr; Einstellungen.
        </div>
      </div>

      <div class="footer" style="background:#faf9f7;border-top:1px solid rgba(96,8,18,0.08);padding:22px 36px;text-align:center;font-size:12px;font-style:italic;color:#8a7a68;font-family:'Atkinson Hyperlegible',Georgia,serif;">
        Responda &middot; Einsatzbereit.
      </div>
    </div>
  </div>
</body>
</html>`
}

module.exports = { buildAlertHtml }
